#!/usr/bin/env python3
"""Install sitecustomize.py into the Hermes venv to register the Doppler
secret source before load_hermes_dotenv() runs.

Run once after installing the plugin:
    python3 ~/.hermes/plugins/doppler_secrets/setup_sitecustomize.py

The file persists across Hermes updates (it lives in site-packages, not
in the Hermes repo). Safe to re-run — idempotent.
"""
import importlib.util
import site
import sys
from pathlib import Path

MARKER = "# hermes-doppler: auto-registered DopplerSource"

BOOTSTRAP = f'''\
"""Auto-generated by hermes-doppler plugin — registers the Doppler secret
source before load_hermes_dotenv() runs. Safe to delete; the plugin will
re-create it on next install."""
{MARKER}
import importlib.util
from pathlib import Path
try:
    _plugin = Path.home() / ".hermes" / "plugins" / "doppler_secrets" / "__init__.py"
    if _plugin.exists():
        _spec = importlib.util.spec_from_file_location("doppler_secrets", str(_plugin))
        _mod = importlib.util.module_from_spec(_spec)
        _spec.loader.exec_module(_mod)
        from agent.secret_sources.registry import register_source
        register_source(_mod.DopplerSource())
except Exception:
    pass
'''


def find_site_packages() -> Path | None:
    """Find the active venv's site-packages directory."""
    # Prefer the venv we're running from
    for p in sys.path:
        if "site-packages" in p and "hermes" in p.lower():
            return Path(p)
    # Fallback: use site module
    paths = site.getsitepackages()
    for p in paths:
        if Path(p).is_dir():
            return Path(p)
    return None


def main() -> None:
    dest = find_site_packages()
    if dest is None:
        print("ERROR: could not find site-packages directory", file=sys.stderr)
        sys.exit(1)

    target = dest / "sitecustomize.py"

    if target.exists():
        content = target.read_text()
        if MARKER in content:
            print(f"Already installed at {target}")
            return
        # Existing sitecustomize.py — append our block
        print(f"Appending Doppler bootstrap to existing {target}")
        target.write_text(content.rstrip() + "\n\n" + BOOTSTRAP)
    else:
        print(f"Creating {target}")
        target.write_text(BOOTSTRAP)

    print(f"Installed. Restart the gateway for the change to take effect.")


if __name__ == "__main__":
    main()
